import{_ as r,C as o,o as s,c as l,E as a,w as t,a as n,a0 as c}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Slovenia Legal Rights","description":"Legal rights for transgender people in Slovenia","frontmatter":{"layout":"doc","title":"Slovenia Legal Rights","description":"Legal rights for transgender people in Slovenia"},"headers":[],"relativePath":"europe/slovenia/legal-rights.md","filePath":"europe/slovenia/legal-rights.md","lastUpdated":null}'),d={name:"europe/slovenia/legal-rights.md"};function g(h,e,p,u,m,f){const i=o("Badge");return s(),l("div",null,[a(i,{variant:"yellow"},{default:t(()=>[...e[0]||(e[0]=[n("Medicalized Recognition",-1)])]),_:1}),a(i,{variant:"green"},{default:t(()=>[...e[1]||(e[1]=[n("Anti-Discrimination Protections",-1)])]),_:1}),a(i,{variant:"green"},{default:t(()=>[...e[2]||(e[2]=[n("Hate Crime Protections",-1)])]),_:1}),e[3]||(e[3]=c('<h1 id="legal-rights-in-slovenia" tabindex="-1">Legal Rights in Slovenia <a class="header-anchor" href="#legal-rights-in-slovenia" aria-label="Permalink to &quot;Legal Rights in Slovenia&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Slovenia operates a <strong>medicalized model</strong> for legal gender recognition, though reforms are under discussion:</p><ul><li><strong>Requirements</strong>: Diagnosis of gender dysphoria from a licensed psychiatrist + evidence of HRT</li><li><strong>Surgery</strong>: Not explicitly required for legal recognition, though medical evidence of treatment (HRT) is needed</li><li><strong>Age</strong>: 18+ can apply independently; 15-18 with parental consent</li><li><strong>Process</strong>: Application to the Administrative Unit (Upravna enota) with medical documentation</li><li><strong>Timeframe</strong>: Typically 2-4 months</li></ul><h3 id="current-process" tabindex="-1">Current Process <a class="header-anchor" href="#current-process" aria-label="Permalink to &quot;Current Process&quot;">​</a></h3><ol><li>Referral from a GP to a psychiatrist or endocrinologist specializing in gender dysphoria</li><li>Diagnosis and treatment plan (HRT)</li><li>Application to the Administrative Unit with medical evidence</li><li>Updated birth certificate, ID card, and passport</li><li>Notification to relevant institutions</li></ol><p><strong>Reform Note</strong>: Civil society organizations (Legebitra, TransAkcija) are advocating for a self-determination model. No legislation has been passed as of 2026.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name change is processed through the <strong>Administrative Unit</strong></li><li>Must align with the gender marker change</li><li>Can be done simultaneously with gender recognition</li><li>Process typically takes 1-2 months</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Slovenia has strong anti-discrimination protections:</p><ul><li><strong>Employment</strong>: Protected under the Employment Relationships Act</li><li><strong>Education</strong>: Protection in schools and universities</li><li><strong>Healthcare</strong>: Access to trans healthcare is legally recognized</li><li><strong>Housing</strong>: General anti-discrimination provisions apply</li><li><strong>Goods and Services</strong>: Protected under the Protection Against Discrimination Act</li></ul><p>The <strong>Protection Against Discrimination Act (ZVarD)</strong> explicitly includes gender identity as a protected characteristic. The <strong>Equal Opportunities Ombudsperson</strong> handles complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> explicitly includes gender identity as a protected characteristic in hate crime provisions (Article 131)</li><li>Enhanced penalties for crimes motivated by transphobia</li><li>Police have specialized LGBTQ+ liaison officers</li><li>Prosecution is improving, with several successful cases in recent years</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Slovenia has biometric ID cards and passports with updated gender markers</li><li>Previous documents are sealed and not publicly accessible</li><li>EU mutual recognition applies for travel within the Schengen Area</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gov.si/drzavni-organi/ministrstva/ministrstvo-za-zdravje/" target="_blank" rel="noreferrer">Slovenian Ministry of Health</a></li><li><a href="https://www.legebitra.si/" target="_blank" rel="noreferrer">Legebitra (LGBTQ+ Organization)</a></li><li><a href="https://transakcija.si/" target="_blank" rel="noreferrer">TransAkcija</a></li><li><a href="https://www.zagovornik.si/" target="_blank" rel="noreferrer">Equal Opportunities Ombudsperson</a></li></ul>',19))])}const y=r(d,[["render",g]]);export{b as __pageData,y as default};
